package rs.ac.ftn.todov1.navigation

import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.remember
import androidx.compose.runtime.setValue
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.lifecycle.viewmodel.compose.viewModel
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import androidx.navigation.navArgument
import rs.ac.ftn.todov1.ui.ZadaciViewModel
import rs.ac.ftn.todov1.ui.detaljizadatka.DetaljiZadatkaScreen
import rs.ac.ftn.todov1.ui.detaljizadatka.DetaljiZadatkaUiState
import rs.ac.ftn.todov1.ui.listazadataka.ListaZadatakaScreen

@Composable
fun ToDoNavHost() {
    val navController = rememberNavController()
    val viewModel: ZadaciViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()

    NavHost(navController = navController, startDestination = ToDoRoutes.LISTA) {
        composable(ToDoRoutes.LISTA) {
            ListaZadatakaScreen(
                uiState = uiState,
                onZadatakClick = { zadatakId -> navController.navigate(ToDoRoutes.detaljiRoute(zadatakId)) },
                onDodajClick = { navController.navigate(ToDoRoutes.NOVI) },
                onPromeniStatus = viewModel::promeniStatus
            )
        }

        composable(ToDoRoutes.NOVI) {
            var detailsState by remember {
                mutableStateOf(DetaljiZadatkaUiState())
            }
            DetaljiZadatkaScreen(
                uiState = detailsState,
                onNazadClick = { navController.navigateUp() },
                onNaslovChange = { detailsState = detailsState.copy(naslov = it) },
                onOpisChange = { detailsState = detailsState.copy(opis = it) },
                onResenChange = { detailsState = detailsState.copy(daLiJeResen = it) },
                onSacuvajClick = {
                    viewModel.sacuvaj(detailsState)
                    detailsState = DetaljiZadatkaUiState()
                    navController.navigateUp()
                },
                onObrisiClick = {
                    navController.navigateUp()
                }
            )
        }

        composable(
            route = ToDoRoutes.DETALJI,
            arguments = listOf(navArgument("zadatakId") { type = NavType.StringType })
        ) { entry ->
            val zadatakId = entry.arguments?.getString("zadatakId").orEmpty()
            val zadatak = viewModel.nadjiZadatak(zadatakId)
            var detailsState by remember(zadatakId, zadatak) {
                mutableStateOf(
                    DetaljiZadatkaUiState(
                        id = zadatak?.id,
                        naslov = zadatak?.naslov.orEmpty(),
                        opis = zadatak?.opis.orEmpty(),
                        daLiJeResen = zadatak?.daLiJeResen ?: false
                    )
                )
            }

            DetaljiZadatkaScreen(
                uiState = detailsState,
                onNazadClick = { navController.navigateUp() },
                onNaslovChange = { detailsState = detailsState.copy(naslov = it) },
                onOpisChange = { detailsState = detailsState.copy(opis = it) },
                onResenChange = { detailsState = detailsState.copy(daLiJeResen = it) },
                onSacuvajClick = {
                    viewModel.sacuvaj(detailsState)
                    navController.navigateUp()
                },
                onObrisiClick = {
                    detailsState.id?.let { viewModel.obrisi(it) }
                    navController.navigateUp()
                }
            )
        }
    }
}

package rs.ac.ftn.todov1.navigation
object ToDoRoutes { const val LISTA = "lista_zadataka" const val NOVI = "novi_zadatak" const val DETALJI = "detalji_zadatka/{zadatakId}"
fun detaljiRoute(zadatakId: String): String = "detalji_zadatka/$zadatakId" }

package rs.ac.ftn.todov1.ui

import androidx.compose.runtime.Composable
import rs.ac.ftn.todov1.navigation.ToDoNavHost

@Composable
fun ToDoApp() {
    ToDoNavHost()
}

package rs.ac.ftn.todov1.ui

import androidx.lifecycle.ViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import rs.ac.ftn.todov1.Zadatak
import rs.ac.ftn.todov1.ui.detaljizadatka.DetaljiZadatkaUiState
import rs.ac.ftn.todov1.ui.listazadataka.ListaZadatakaUiState
import java.util.UUID

class ZadaciViewModel : ViewModel() {
    private val _uiState = MutableStateFlow(ListaZadatakaUiState(zadaci = pocetniZadaci()))
    val uiState: StateFlow<ListaZadatakaUiState> = _uiState.asStateFlow()

    fun promeniStatus(zadatakId: String) {
        _uiState.update { state ->
            state.copy(
                zadaci = state.zadaci.map { zadatak ->
                    if (zadatak.id == zadatakId) {
                        zadatak.copy(daLiJeResen = !zadatak.daLiJeResen)
                    } else {
                        zadatak
                    }
                }
            )
        }
    }

    fun nadjiZadatak(zadatakId: String): Zadatak? =
        _uiState.value.zadaci.firstOrNull { it.id == zadatakId }

    fun sacuvaj(detalji: DetaljiZadatkaUiState) {
        if (detalji.naslov.isBlank()) return

        val zadatak = Zadatak(
            id = detalji.id ?: UUID.randomUUID().toString(),
            naslov = detalji.naslov,
            opis = detalji.opis,
            daLiJeResen = detalji.daLiJeResen
        )

        _uiState.update { state ->
            val postoji = state.zadaci.any { it.id == zadatak.id }
            state.copy(
                zadaci = if (postoji) {
                    state.zadaci.map { if (it.id == zadatak.id) zadatak else it }
                } else {
                    listOf(zadatak) + state.zadaci
                }
            )
        }
    }

    fun obrisi(zadatakId: String) {
        _uiState.update { state ->
            state.copy(zadaci = state.zadaci.filterNot { it.id == zadatakId })
        }
    }

    private fun pocetniZadaci(): List<Zadatak> = listOf(
        Zadatak(
            id = "1",
            naslov = "Припремити вежбе",
            opis = "Проверити примере и задатке за термин.",
            daLiJeResen = false
        ),
        Zadatak(
            id = "2",
            naslov = "Обновити Compose state",
            opis = "remember, rememberSaveable и state hoisting.",
            daLiJeResen = true
        ),
        Zadatak(
            id = "3",
            naslov = "Написати домаћи",
            opis = "Задатак из ToDo блока.",
            daLiJeResen = false
        )
    )
}

package rs.ac.ftn.todov1.ui.detaljizadatka

import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.fillMaxWidth
import androidx.compose.foundation.layout.padding
import androidx.compose.material3.Button
import androidx.compose.material3.Checkbox
import androidx.compose.material3.ExperimentalMaterial3Api
import androidx.compose.material3.IconButton
import androidx.compose.material3.OutlinedTextField
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.material3.TopAppBar
import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun DetaljiZadatkaScreen(
    uiState: DetaljiZadatkaUiState,
    onNazadClick: () -> Unit,
    onNaslovChange: (String) -> Unit,
    onOpisChange: (String) -> Unit,
    onResenChange: (Boolean) -> Unit,
    onSacuvajClick: () -> Unit,
    onObrisiClick: () -> Unit
) {
    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(if (uiState.id == null) "Нови задатак" else "Детаљи") },
                navigationIcon = {
                    IconButton(onClick = onNazadClick) {
                        Text("←")
                    }
                },
                actions = {
                    if (uiState.id != null) {
                        IconButton(onClick = onObrisiClick) {
                            Text("✕")
                        }
                    }
                }
            )
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .padding(16.dp)
        ) {
            OutlinedTextField(
                value = uiState.naslov,
                onValueChange = onNaslovChange,
                label = { Text("Наслов") },
                modifier = Modifier.fillMaxWidth()
            )

            OutlinedTextField(
                value = uiState.opis,
                onValueChange = onOpisChange,
                label = { Text("Опис") },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(top = 12.dp)
            )

            Row(modifier = Modifier.padding(top = 8.dp)) {
                Checkbox(checked = uiState.daLiJeResen, onCheckedChange = onResenChange)
                Text("Завршен", modifier = Modifier.padding(top = 12.dp))
            }

            Button(
                onClick = onSacuvajClick,
                modifier = Modifier.padding(top = 16.dp)
            ) {
                Text("Сачувај")
            }
        }
    }
}

package rs.ac.ftn.todov1.ui.listazadataka

import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.Arrangement
import androidx.compose.foundation.layout.Column
import androidx.compose.foundation.layout.Row
import androidx.compose.foundation.layout.fillMaxSize
import androidx.compose.foundation.layout.fillMaxWidth
import androidx.compose.foundation.layout.padding
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.Checkbox
import androidx.compose.material3.ExperimentalMaterial3Api
import androidx.compose.material3.FloatingActionButton
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.material3.TopAppBar
import androidx.compose.material3.TopAppBarDefaults
import androidx.compose.runtime.Composable
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ListaZadatakaScreen(
    uiState: ListaZadatakaUiState,
    onZadatakClick: (String) -> Unit,
    onDodajClick: () -> Unit,
    onPromeniStatus: (String) -> Unit
) {
    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("ToDo") },
                colors = TopAppBarDefaults.topAppBarColors()
            )
        },
        floatingActionButton = {
            FloatingActionButton(onClick = onDodajClick) {
                Text("+")
            }
        }
    ) { innerPadding ->
        if (uiState.zadaci.isEmpty()) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(innerPadding),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Text("Нема задатака")
            }
        } else {
            LazyColumn(
                modifier = Modifier
                    .fillMaxSize()
                    .padding(innerPadding)
            ) {
                items(items = uiState.zadaci, key = { it.id }) { zadatak ->
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 16.dp, vertical = 12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(
                            modifier = Modifier
                                .weight(1f)
                                .clickable { onZadatakClick(zadatak.id) }
                        ) {
                            Text(zadatak.naslov, style = MaterialTheme.typography.titleMedium)
                            if (zadatak.opis.isNotBlank()) {
                                Text(zadatak.opis, style = MaterialTheme.typography.bodyMedium)
                            }
                        }
                        Checkbox(
                            checked = zadatak.daLiJeResen,
                            onCheckedChange = { onPromeniStatus(zadatak.id) }
                        )
                    }
                }
            }
        }
    }
}

package rs.ac.ftn.todov1.ui.theme

import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.darkColorScheme
import androidx.compose.material3.lightColorScheme
import androidx.compose.runtime.Composable

private val LightColors = lightColorScheme(
    primary = TealPrimary,
    secondary = TealSecondary,
    background = CreamBackground
)

private val DarkColors = darkColorScheme(
    primary = TealSecondary,
    secondary = TealPrimary
)

@Composable
fun ToDoV1Theme(
    darkTheme: Boolean = false,
    content: @Composable () -> Unit
) {
    MaterialTheme(
        colorScheme = if (darkTheme) DarkColors else LightColors,
        typography = Typography,
        content = content
    )
}

